import java.lang.Math;
import java.util.Arrays;

public static long solve(long[] nums) {
    int n = nums.length;
    if (n < 3) {
        return 0;
    }

    // Create a mutable copy of the array to perform modifications
    long[] currentNums = new long[n];
    System.arraycopy(nums, 0, currentNums, 0, n);

    long totalCost = 0;

    // To maximize the number of peaks, we target non-adjacent indices: 1, 3, 5, ...
    // This achieves the maximum possible number of peaks: ceil((N-2)/2).

    // Iterate i from 1 up to N-2, stepping by 2.
    for (int i = 1; i <= n - 2; i += 2) {
        // For i to be a peak, currentNums[i] must be strictly greater than both neighbors.
        // Required value R_i = max(currentNums[i-1], currentNums[i+1]) + 1

        long neighborMax = Math.max(currentNums[i - 1], currentNums[i + 1]);
        long requiredValue = neighborMax + 1;

        long currentValue = currentNums[i];

        if (requiredValue > currentValue) {
            long cost = requiredValue - currentValue;
            totalCost += cost;

            // Update the array value to the minimum required height
            currentNums[i] = requiredValue;
        }
    }

    return totalCost;
}
