import java.util.Arrays;
import java.util.Scanner;

public class Solution {

    /**
     * Solves the problem by finding the minimum cost to achieve the maximum possible
     * number of special indices (peaks) using Dynamic Programming on the path graph
     * formed by potential peak locations.
     * 
     * @param nums The input array.
     * @return The minimum total operation count.
     */
    public static long solve(long[] nums) {
        int N = nums.length;

        if (N < 3) {
            return 0;
        }

        // Potential peak indices are from 1 to N-2.
        int N_eff = N - 2;

        // Maximum number of non-adjacent peaks achievable.
        int K_max = (N_eff + 1) / 2;

        // 1. Calculate costs C_i for i = 1 to N-2.
        long[] C = new long[N]; // Use 1-based indexing for convenience, C[0] unused
        for (int i = 1; i <= N_eff; i++) {
            // Cost C_i = max(0, max(nums[i-1], nums[i+1]) + 1 - nums[i])
            long required_height = Math.max(nums[i - 1], nums[i + 1]) + 1;
            long cost = Math.max(0L, required_height - nums[i]);
            C[i] = cost;
        }

        // 2. Dynamic Programming
        // DP[k][0]: Minimum cost using exactly k peaks ending at the previous index (i-1), where i-1 was NOT chosen.
        // DP[k][1]: Minimum cost using exactly k peaks ending at the previous index (i-1), where i-1 WAS chosen.

        final long INF = Long.MAX_VALUE / 2; // Safe infinity

        // DP state size: (K_max + 1) x 2
        long[][] dp = new long[K_max + 1][2];

        for (int k = 0; k <= K_max; k++) {
            Arrays.fill(dp[k], INF);
        }

        // Base case: 0 peaks chosen, ending state is 'not taken' (dummy start)
        dp[0][0] = 0;

        // Iterate through potential peak indices i = 1 to N-2
        for (int i = 1; i <= N_eff; i++) {
            long[][] next_dp = new long[K_max + 1][2];
            for (int k = 0; k <= K_max; k++) {
                next_dp[k][0] = INF;
                next_dp[k][1] = INF;
            }

            for (int k = 0; k <= K_max; k++) {

                // Transition for current index i NOT being taken (next_dp[k][0])
                // Can transition from previous state k, whether i-1 was taken or not.
                next_dp[k][0] = Math.min(dp[k][0], dp[k][1]);

                // Transition for current index i BEING taken (next_dp[k+1][1])
                // Must transition from previous state k, where i-1 was NOT taken (dp[k][0]).
                if (k + 1 <= K_max) {
                    if (dp[k][0] != INF) {
                        long new_cost = dp[k][0] + C[i];
                        next_dp[k + 1][1] = Math.min(next_dp[k + 1][1], new_cost);
                    }
                }
            }
            dp = next_dp;
        }

        // The answer is the minimum cost to achieve K_max peaks, regardless of whether the last index N-2 was chosen or not.
        long result = Math.min(dp[K_max][0], dp[K_max][1]);

        return result;
    }
}

